// Multi-file example — the entry. It calls registerScript(), so the build emits
// it as a loadable dist/examples/multi-file/main.mjs. Its `./lib/format` import
// is INLINED into that one file by esbuild — nothing else to deploy.
//
// Build it like any other script (`npm run build`); load the single produced
// .mjs. Relative imports need no file extension — the bundler resolves them.

import { fmtPos, ORIGIN } from "./lib/format";

const script = registerScript({ name: "MultiFileDemo", version: "0.1.0", authors: ["you"] });

script.registerModule({
    name: "MultiFileDemo",
    category: "Misc",
    description: "Demonstrates splitting a script across files (bundled into one .mjs).",
}, (mod) => {
    mod.on("enable", () => {
        Client.displayChatMessage(`§a[MultiFileDemo] enabled — helper from ${ORIGIN}`);
    });

    mod.on("playerJump", () => {
        const p = mc.player;
        if (p === null) return;
        const pos = p.position();
        Client.displayChatMessage(`§e[MultiFileDemo] jumped at ${fmtPos(pos.x, pos.y, pos.z)}`);
    });
});

/// <reference types="@wunk/lb-script-api-types/ambient" />
//
// nearest-mob.ts — every N ticks, prints the nearest entity to the player and
// its distance.
//
// What this starter showcases:
//   • `Setting.float` with a `range:` for a continuous slider, and
//     `Setting.int` for the tick interval (throttling).
//   • Iterating world entities via `mc.level.entitiesForRendering()` and
//     filtering manually.
//   • A neat TS trick to type the loop's "best so far" without naming the
//     entity class: take the element type of the (typed) entity list, so
//     `nearest` is `Entity | null` and its methods are checked.
//   • Squared-distance comparison inside the loop (only one `Math.sqrt` at
//     the end) and a tick-counter throttle so we don't spam chat.
//
// Prereqs: be in a world with mobs nearby.

const script = registerScript({
    name: "NearestMobTS",
    version: "0.1.0",
    authors: ["you"],
});

const RANGE = Setting.float({
    name: "range",
    default: 16.0,
    range: [4.0, 64.0],
});

const INTERVAL_TICKS = Setting.int({
    name: "intervalTicks",
    default: 20, // once per second at 20 TPS
    range: [5, 200],
});

script.registerModule({
    name: "NearestMobTS",
    category: "Misc",
    description: "Prints the nearest entity and its distance periodically.",
}, (mod) => {
    let ticks = 0;

    mod.on("playerTick", () => {
        if (!mc.player) return;
        ticks++;
        if (ticks % INTERVAL_TICKS.get() !== 0) return;

        const me = mc.player;
        const myPos = me.position();
        const myId = me.getId();
        const range = RANGE.get();

        // Materialise the iterable so we can name its element type below.
        const entities = [...mc.level.entitiesForRendering()];
        // `nearest` is the element type (an Entity) or null — fully typed.
        let nearest: (typeof entities)[number] | null = null;
        let bestDistSq = range * range;

        for (const e of entities) {
            if (e.getId() === myId) continue;
            const p = e.position();
            const dx = myPos.x - p.x;
            const dy = myPos.y - p.y;
            const dz = myPos.z - p.z;
            const dSq = dx * dx + dy * dy + dz * dz;
            if (dSq < bestDistSq) {
                bestDistSq = dSq;
                nearest = e;
            }
        }

        if (nearest) {
            const dist = Math.sqrt(bestDistSq);
            const name = nearest.getName().getString();
            Client.displayChatMessage(
                `§b[NearestMob] ${name} @ ${dist.toFixed(2)} blocks`
            );
        }
    });
});

/// <reference types="@wunk/lb-script-api-types/ambient" />
//
// timed-pinger.ts — while enabled, sends a configurable chat message every N
// seconds using `AsyncUtil.ticks(...)` + `async`/`await`.
//
// What this starter showcases:
//   • An `async` event handler (the `enable` handler returns a promise).
//   • `await AsyncUtil.ticks(n)` to pause without blocking the game loop —
//     the "do something every N ticks" idiom in scripts.
//   • A closure "generation" counter set in `disable` to break the async
//     loop cleanly, so a stale loop from a previous enable doesn't keep
//     firing after the user toggles the module off.
//   • `Setting.text` + `Setting.int` (with a `range`) for live config.
//
// Prereqs: be in a world (or on a server) where chat is visible.
//
// SAFETY: this WILL send chat messages on a timer. Don't ship to a server
// that bans chat macros, and don't set the interval too low.

const script = registerScript({
    name: "TimedPingerTS",
    version: "0.1.0",
    authors: ["you"],
});

const MESSAGE = Setting.text({
    name: "message",
    default: "ping",
});

const INTERVAL_SECONDS = Setting.int({
    name: "intervalSeconds",
    default: 30,
    range: [5, 3600],
});

script.registerModule({
    name: "TimedPingerTS",
    category: "Misc",
    description: "Sends a chat message every N seconds while enabled.",
}, (mod) => {
    // Each enable creates a new generation; disable bumps it so any
    // still-suspended `await` loop notices it's stale and exits.
    let generation = 0;

    mod.on("enable", async () => {
        const myGen = ++generation;
        Client.displayChatMessage("§a[TimedPinger] started");

        while (generation === myGen) {
            // Minecraft runs at 20 ticks per second, so N seconds = N*20 ticks.
            await AsyncUtil.ticks(INTERVAL_SECONDS.get() * 20);
            // After the await resumes the user may have disabled (or
            // toggled-off-then-on) the module while we were sleeping — recheck
            // BEFORE sending, else a stale loop fires one extra message.
            if (generation !== myGen) break;
            NetworkUtil.sendChatMessage(MESSAGE.get());
        }
    });

    mod.on("disable", () => {
        generation++;
        Client.displayChatMessage("§c[TimedPinger] stopped");
    });
});

