// lb-inject "always-on" example (TypeScript port of inject-always-on.js).
//
// Installs its hooks at load time and keeps them active for the whole session.
// Registers NO module — there's nothing to toggle. Build with `npm run build`
// and load dist/examples/always-on.mjs into LiquidBounce.

import { Inject } from "lb-inject";

// A script must still call registerScript(...) even with no module.
registerScript({ name: "InjectAlwaysOn", version: "1.0.0", authors: ["Obus"] });

const System_ = Java.type("java.lang.System");

// Idempotency guard: `.script reload` re-runs scripts, which would stack
// duplicate injections. A bootstrap System property (visible across script
// contexts), namespaced by library version, installs at most once per session.
const SENTINEL = "nf.alwayson.installed." + Inject.VERSION;
if (System_.getProperty(SENTINEL) === null) {
  try {
    let ticks = 0;
    // Minecraft.tick fires continuously (even at the main menu) → genuinely
    // always-on. Heartbeat roughly once a minute.
    Inject.inject("net.minecraft.client.Minecraft", "tick", "RETURN", () => {
      if (++ticks % 1200 === 0) {
        Client.displayChatMessage(`§b[InjectAlwaysOn] tick hook alive — ${ticks} ticks`);
      }
    });
    System_.setProperty(SENTINEL, "true");
    Client.displayChatMessage("§a[InjectAlwaysOn] hook installed (active for the whole session)");
  } catch (e) {
    Client.displayChatMessage("§c[InjectAlwaysOn] failed to install: " + e);
  }
} else {
  Client.displayChatMessage("§e[InjectAlwaysOn] already installed this session — skipping re-inject");
}

// Declarative, mixin-style injection.
//
// The starter (main.ts) wires hooks imperatively inside on("enable")/on("disable").
// A real mixin is just *declared*, not toggled by hand. `Inject.module(...)` gives
// you that: declare the hooks once as data, and the library applies them when the
// module enables and removes them when it disables.
//
// (For hooks that should stay active for the whole session — the closest thing to
// a statically-declared mixin — use `Inject.always("key", [...])` instead, with no
// module. See the lb-inject README.)

import { Inject } from "lb-inject";

const script = registerScript({ name: "MixinStyle", version: "1.0.0", authors: ["Obus"] });

const MC = "net.minecraft.client.Minecraft";
let ticks = 0;

script.registerModule(
  { name: "MixinStyle", category: "Misc", description: "Declarative (mixin-style) injection via Inject.module" },
  (mod) => {
    // Declared, not hand-wired. Two forms, both accepted:
    Inject.module(mod, [
      // tuple form — same arg order as Inject.inject(...)
      [MC, "tick", "RETURN", () => {
        if (++ticks % 200 === 0) Client.displayChatMessage(`§b[MixinStyle] ${ticks} ticks`);
      }],
      // object form — reads like a mixin @At
      { class: MC, method: "getFps", at: "HEAD", hook: () => { /* runs on every getFps() */ } },
      // a call-SITE hook needs `target`; the type enforces it for BEFORE_INVOKE
      { class: MC, method: "tick", at: "BEFORE_INVOKE", hook: () => {}, target: `${MC}.getFps` },
    ]);
    // No on("enable")/on("disable") here — Inject.module added them for us.
  },
);

// lb-inject × @wunk/lb-script-api-types — typed injection targets.
//
// THE POINT OF THIS FILE: lb-inject takes the target class+method as plain
// STRINGS — `Inject.inject("net.minecraft.client.Minecraft", "getFps", ...)`.
// A typo ("getFsp") or a method that doesn't exist on that class fails only at
// runtime, deep inside the agent. But we already ship a full type tree for
// every JVM class (the script-api-types package). This example builds a thin
// typed facade over `Inject` that uses those types to CHECK the method name at
// compile time — so a bad target is a red squiggle, not a runtime surprise.
//
// This is the "what does typing unlock" demo from the README's Ideas section.

import { Inject } from "lb-inject";
import type { Minecraft } from "@wunk/lb-script-api-types/types/net/minecraft/client/Minecraft";

// --- the typed facade -------------------------------------------------------
// MethodKeys<T> = the names of T's callable members. If T has none (or is
// loosely typed), MethodNames<T> degrades to `string`, so the facade never
// gets in your way for classes whose types are sparse.
type MethodKeys<T> = { [K in keyof T]-?: T[K] extends (...args: any[]) => any ? K : never }[keyof T] & string;
type MethodNames<T> = [MethodKeys<T>] extends [never] ? string : MethodKeys<T>;

/** Patch the HEAD of `T#method`, with `method` checked against T's real members. */
function injectHead<T>(fqcn: string, method: MethodNames<T>, hook: () => void) {
  return Inject.inject(fqcn, method, "HEAD", hook);
}

/** Patch the RETURN of `T#method`. */
function injectReturn<T>(fqcn: string, method: MethodNames<T>, hook: () => void) {
  return Inject.inject(fqcn, method, "RETURN", hook);
}

// --- usage ------------------------------------------------------------------
registerScript({ name: "TypedTargets", version: "1.0.0", authors: ["Obus"] });

let calls = 0;

// `"getFps"` autocompletes from Minecraft's typed members and is verified to
// exist. Pass `<Minecraft>` as the type arg; the facade constrains `method`.
injectHead<Minecraft>("net.minecraft.client.Minecraft", "getFps", () => { calls++; });

injectReturn<Minecraft>("net.minecraft.client.Minecraft", "tick", () => {
  if (calls > 0 && calls % 600 === 0) {
    Client.displayChatMessage(`§b[TypedTargets] getFps called ${calls}x`);
  }
});

// A method that doesn't exist on Minecraft is a COMPILE error — uncomment to see:
//   injectHead<Minecraft>("net.minecraft.client.Minecraft", "totallyNotAMethod", () => {});
// @ts-expect-error — "totallyNotAMethod" is not a member of Minecraft
const _badTarget: MethodNames<Minecraft> = "totallyNotAMethod";
void _badTarget;

Client.displayChatMessage("§a[TypedTargets] typed hooks installed");

